  .map(([key, value]) => encodeURIComponent(key) + '=' + encodeURIComponent(value))
  .join('&');

let rows;
try {
  rows = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/tenants?' + qs,
    headers: {
      apikey: serviceKey,
      Authorization: 'Bearer ' + serviceKey,
    },
    json: true,
  });
} catch (error) {
  return [{
    json: {
      ...input,
      authorized: false,
      http_status: 502,
      error: 'Tenant auth lookup failed',
      provider_error: String(error?.message || error).slice(0, 500),
    }
  }];
}

const tenant = Array.isArray(rows) ? rows[0] : null;

if (!tenant?.tenant_id) {
  return [{
    json: {
      ...input,
      authorized: false,
      http_status: 401,
      error: 'Unauthorized tenant or api_token',
    }
  }];
}

return [{
  json: {
    ...input,
    authorized: true,
    tenant_record: tenant,
    tenant_id: tenant.tenant_id,
    billing_email: tenant.billing_email || tenant.mail || input.email || '',
    stripe_customer_id: tenant.stripe_customer_id || '',
    http_status: 200,
  }
}];

const input = $json;
const secretKey = String($env.STRIPE_SECRET_KEY || '').trim();

if (!secretKey) {
  return [{
    json: {
      ...input,
      http_status: 500,
      error: 'Missing STRIPE_SECRET_KEY'
    }
  }];
}

if (!input.stripe_customer_id) {
  return [{
    json: {
      ...input,
      http_status: 400,
      error: 'Missing stripe_customer_id for portal session'
    }
  }];
}

const formBody = [
  ['customer', input.stripe_customer_id],
  ['return_url', String($env.STRIPE_PORTAL_RETURN_URL || $env.STRIPE_SUCCESS_URL || 'https://dashboard.zirel.org?tab=abbonamento')],
]
  .map(([key, value]) => encodeURIComponent(key) + '=' + encodeURIComponent(String(value)))
  .join('&');

let data;
try {
  data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.stripe.com/v1/billing_portal/sessions',
    headers: {
      Authorization: 'Bearer ' + secretKey,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: formBody,
    json: true,
  });
} catch (error) {
  return [{
    json: {
      ...input,
      http_status: 502,
      error: 'Stripe portal creation failed',
      stripe_error: String(error?.message || error).slice(0, 1000),
    }
  }];
}

return [{
  json: {
    ...input,
    url: data.url,
    stripe_portal_session_id: data.id,
    stripe_raw: data,
    http_status: 200,
  }
}];

const event = $json.body || {};
const object = event.data?.object || {};
const priceId = object.items?.data?.[0]?.price?.id || object.plan?.id || '';
const productId = object.items?.data?.[0]?.price?.product || object.plan?.product || '';
const tenantId = object.client_reference_id || object.metadata?.tenant_id || '';
const billingEmail = object.customer_details?.email || object.customer_email || object.receipt_email || '';
const businessName = object.metadata?.business_name || object.metadata?.hotel_name || object.metadata?.nome_attivita || tenantId || 'Zirèl';
const trialEndsAt = object.trial_end ? new Date(object.trial_end * 1000).toISOString() : null;

let planCode = '';
let billingCycle = 'monthly';

const priceBaseMonthly = String($env.STRIPE_PRICE_BASE_ID || $env.STRIPE_PRICE_BASE_MONTHLY_ID || '');
const pricePremiumMonthly = String($env.STRIPE_PRICE_PREMIUM_ID || $env.STRIPE_PRICE_PREMIUM_MONTHLY_ID || '');
const priceBaseYearly = String($env.STRIPE_PRICE_BASE_YEARLY_ID || '');
const pricePremiumYearly = String($env.STRIPE_PRICE_PREMIUM_YEARLY_ID || '');

if (priceId) {
  if (priceId === pricePremiumMonthly) planCode = 'premium';
  else if (priceId === priceBaseMonthly) planCode = 'base';
  else if (priceId === pricePremiumYearly) { planCode = 'premium'; billingCycle = 'yearly'; }
  else if (priceId === priceBaseYearly) { planCode = 'base'; billingCycle = 'yearly'; }
}

const currentPeriodEnd = object.current_period_end ? new Date(object.current_period_end * 1000).toISOString() : null;
const isSetupFeePaid = event.type === 'checkout.session.completed' ? true : undefined;

return [{
  json: {
    raw_event: event,
    event_type: String(event.type || ''),
    event_id: String(event.id || ''),
    tenant_id: tenantId,
    customer_id: String(object.customer || ''),
    subscription_id: String(object.subscription || object.id || ''),
    billing_email: billingEmail,
    business_name: businessName,
    trial_ends_at: trialEndsAt,
    stripe_price_id: priceId,
    stripe_product_id: productId,
    billing_plan_code: planCode,
    billing_cycle: billingCycle,
    current_period_end: currentPeriodEnd,
    setup_fee_paid: isSetupFeePaid,
    subscription_status: event.type === 'customer.subscription.deleted'
      ? 'canceled'
      : event.type === 'invoice.payment_failed'
        ? 'past_due'
        : String(object.status || 'active'),
  },
}];

const input = $json || {};
const tenantId = String(input.tenant_id || '').trim();
const eventType = String(input.event_type || '').trim();
const billingEmail = String(input.billing_email || '').trim().toLowerCase();
const internalEmail = String($env.ZIREL_BILLING_ALERT_EMAIL || '').trim().toLowerCase();
const eventId = String(input.event_id || '').trim() || ('manual-' + Date.now());
const businessName = input.business_name || input.tenant_id || 'Zirèl';

if (!tenantId || !eventType) {
  return [];
}

const basePayload = {
  tenant_id: tenantId,
  business_name: businessName,
  billing_email: billingEmail || null,
  billing_plan_code: input.billing_plan_code || null,
  billing_cycle: input.billing_cycle || null,
  current_period_end: input.current_period_end || null,
  trial_ends_at: input.trial_ends_at || null,
  subscription_status: input.subscription_status || null,
  event_id: eventId,
  dashboard_url: 'https://dashboard.zirel.org?tab=abbonamento',
  portal_url: 'https://dashboard.zirel.org?tab=abbonamento',
};

const makeRow = (channel, templateKey, recipient, suffix) => ({
  json: {
    tenant_id: tenantId,
    channel,
    template_key: templateKey,
    related_entity_type: 'billing_subscription',
    related_entity_id: input.subscription_id || tenantId,
    status: 'pending',
    retry_count: 0,
    max_retries: 5,
    next_retry_at: new Date().toISOString(),
    trace_id: 'billing-event:' + eventType + ':' + eventId,
    recipient_email: recipient,
    dedupe_key: tenantId + ':' + eventType + ':' + suffix + ':' + eventId,
    payload: basePayload,
  },
});

const rows = [];

if (eventType === 'invoice.payment_failed') {
  if (billingEmail) rows.push(makeRow('email_billing_customer', 'billing_payment_failed', billingEmail, 'customer'));
  if (internalEmail) rows.push(makeRow('email_billing_internal', 'billing_payment_failed_internal', internalEmail, 'internal'));
} else if (eventType === 'invoice.paid') {
  if (billingEmail) rows.push(makeRow('email_billing_customer', 'billing_payment_succeeded', billingEmail, 'customer'));
} else if (eventType === 'customer.subscription.deleted') {
  if (billingEmail) rows.push(makeRow('email_billing_customer', 'billing_subscription_canceled', billingEmail, 'customer'));
  if (internalEmail) rows.push(makeRow('email_billing_internal', 'billing_subscription_canceled_internal', internalEmail, 'internal'));
} else if (eventType === 'customer.subscription.trial_will_end') {
  if (billingEmail) rows.push(makeRow('email_billing_customer', 'billing_trial_ending', billingEmail, 'customer'));
}

return rows;
